/**
 * Bibliothèque CRFPA — type definitions for the library catalog.
 * The manifest is auto-generated by scripts/build-library-assets.ts.
 */

export type LibraryFormat =
  | 'pdf'           // file lives at `${path}` and is rendered via PdfScrollViewer
  | 'html'          // sanitized HTML, fetched + DOMPurify
  | 'markdown'      // markdown text from a JSON chunks file
  | 'code-tree'     // structured chunked JSON (id/codeName/num/breadcrumb/text), tree view
  | 'grand-arret'   // imported from grandsArretsSeed.ts at runtime, structured render

export type LibraryCategory =
  | 'codes'
  | 'grands-arrets'
  | 'cc'
  | 'textes'
  | 'crfpa-officiel'
  | 'rapports'

export interface LibraryEntry {
  /** Stable slug, e.g. 'code-civil', 'sujet-2023-obligations', 'gajc-blanco'. */
  id: string
  category: LibraryCategory
  title: string
  /** Free-form short subtitle (e.g. "Cass. ch. réunies, 8 février 1873"). */
  subtitle?: string
  format: LibraryFormat
  /** Public URL the viewer fetches from (PDF/HTML/JSON), or runtime slug for grands-arrets. */
  path: string
  /** Approximate size of the underlying file, in KB. Used for UX hints. */
  sizeKb: number
  /** Year if obvious from filename or metadata. */
  year?: number
  /** CRFPA matière if applicable (obligations, civil, penal, …). */
  matiere?: string
  /** Free-form tags for filtering. */
  tags: string[]
}
